<?php namespace Tests\Unit\Services; use Tests\TestCase; use App\Services\Sales\OrderService; use App\Models\Sales\SalesOrder; class OrderServiceTest extends TestCase { public function test_create_order() { $service = app(OrderService::class); $order = $service->create(['status' => 'DRAFT', 'total' => 1000]); $this->assertInstanceOf(SalesOrder::class, $order); $this->assertEquals('DRAFT', $order->status); } public function test_immutable_order_cannot_approve() { $order = SalesOrder::create(['id' => \Illuminate\Support\Str::uuid(), 'order_number' => 'SO-001', 'status' => 'SUBMITTED', 'created_by' => \Illuminate\Support\Str::uuid()]); $this->assertTrue($order->isImmutable()); } }
